import{_ as l,c as a,o as e,ag as o}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduce/live/哔哩哔哩.md","filePath":"guide/introduce/live/哔哩哔哩.md","lastUpdated":1743997479000}'),c={name:"guide/introduce/live/哔哩哔哩.md"};function d(t,i,s,n,r,h){return e(),a("div",null,i[0]||(i[0]=[o('<div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>哔哩哔哩录制480P以上画质需cookies支持，可在<code>投稿管理</code>右上角→<code>新增</code>通过，<code>扫码登陆、本地cookis文件</code>进行加载。</li><li>多数直播分区都是<code>HLS</code>流，需要用到<code>streamlink</code>下载器，该下载器依赖<code>ffmpeg</code>，请确认是否安装，详见<a href="./../Config/GlobalConfig.html#下载插件-downloader">下载器的选择</a></li><li>重要功能将使用⭐符号来进行标注，请注意查看。</li></ul></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><ul><li>请勿使用网上购买的cookies<code>协议号</code>来进行加载登陆，此类<strong>黑号</strong>缺失必要的<code>值</code>。</li></ul></div><h2 id="画质等级-bili-qn" tabindex="-1">画质等级（bili_qn） <a class="header-anchor" href="#画质等级-bili-qn" aria-label="Permalink to &quot;画质等级（bili_qn）&quot;">​</a></h2><ul><li>默认为原画画质，如果觉得画质很糊，请根据<code>日志</code>来判断下载的流分辨率是否与主播一致，不建议进行修改。</li><li>刚开播如果无选择的画质，会先录制原画， 后续视频分段时，如果下载插件为非<code>stream-gears</code>，会切换到选择的画质。</li></ul><hr><h2 id="弹幕录制" tabindex="-1">弹幕录制 <a class="header-anchor" href="#弹幕录制" aria-label="Permalink to &quot;弹幕录制&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>开启弹幕录制后，录制所使用的cookies账号会在对应直播间的<code>高能榜</code>出现，如果你不能接受，那么就默认关闭即可。</li></ul></div><h3 id="录制弹幕-bilibili-danmaku" tabindex="-1">录制弹幕（bilibili_danmaku） <a class="header-anchor" href="#录制弹幕-bilibili-danmaku" aria-label="Permalink to &quot;录制弹幕（bilibili_danmaku）&quot;">​</a></h3><ul><li>录制哔哩哔哩弹幕，目前不支持视频按时长分段下的弹幕文件自动分段。仅限下载插件为非 stream-gears 时生效，默认关闭。</li></ul><h3 id="录制详细弹幕-bilibili-danmaku-detail" tabindex="-1">录制详细弹幕（bilibili_danmaku_detail） <a class="header-anchor" href="#录制详细弹幕-bilibili-danmaku-detail" aria-label="Permalink to &quot;录制详细弹幕（bilibili_danmaku_detail）&quot;">​</a></h3><ul><li>录制的弹幕信息中包含<code>发送者昵称、用户UID</code>，同时保存<code>醒目留言、上舰、礼物</code>信息。</li></ul><h3 id="录制完整弹幕-bilibili-danmaku-raw" tabindex="-1">录制完整弹幕（bilibili_danmaku_raw） <a class="header-anchor" href="#录制完整弹幕-bilibili-danmaku-raw" aria-label="Permalink to &quot;录制完整弹幕（bilibili_danmaku_raw）&quot;">​</a></h3><ul><li>原始弹幕信息，方便有技术能力的用户对主播弹幕数据进行统计（实验性质：可能导致弹幕文件巨大）</li></ul><hr><h2 id="哔哩哔哩-cookies" tabindex="-1">哔哩哔哩 Cookies <a class="header-anchor" href="#哔哩哔哩-cookies" aria-label="Permalink to &quot;哔哩哔哩 Cookies&quot;">​</a></h2><h3 id="哔哩哔哩-cookie-文本-bili-cookie" tabindex="-1">哔哩哔哩 Cookie 文本（bili_cookie） <a class="header-anchor" href="#哔哩哔哩-cookie-文本-bili-cookie" aria-label="Permalink to &quot;哔哩哔哩 Cookie 文本（bili_cookie）&quot;">​</a></h3><ul><li>即使有了<code>biliup-rs</code>的扫码登录方式，但我们仍提供了该选项来用于用户自己获取cookies来填入，你需要获取到以下几个值来填入保存。</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SESSDATA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">none</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;bili_jct</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">none</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;DedeUserID__ckMd5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">none</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;DedeUserID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">none</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h3 id="哔哩哔哩-cookie-文件-bili-cookie-file" tabindex="-1">哔哩哔哩 Cookie 文件（bili_cookie_file） <a class="header-anchor" href="#哔哩哔哩-cookie-文件-bili-cookie-file" aria-label="Permalink to &quot;哔哩哔哩 Cookie 文件（bili_cookie_file）&quot;">​</a></h3><ul><li>如果你按照此页面上的<code>IMPORTANT</code>扫码添加了B站<code>账号</code>，那么可在这一步点击选择自己的账号信息。</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>当文本与文件同时存在，将优先加载文件（bili_cookie_file）。</li></ul></div><hr><h2 id="⭐直播流协议-bili-protocol" tabindex="-1">⭐直播流协议（bili_protocol） <a class="header-anchor" href="#⭐直播流协议-bili-protocol" aria-label="Permalink to &quot;⭐直播流协议（bili_protocol）&quot;">​</a></h2><ul><li>无论直播间是否为<code>HLS</code>流，都建议将此选项修改为<code>hls_fmp4</code>，开启后如不是<code>HLS</code>流程序会默认退到<code>ffmpeg</code>进行录制。</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>⭐多数B站直播间无法录制都是因为这个原因，只要把默认的<code>下载器</code>改为ffmpeg或streamlink来录制，并将此选项设置为<code>hls_fmp4</code>后保存重启即可。</li><li><code>stream-gears</code>尚未支持<code>hls_fmp4</code>。</li></ul></div><hr><h2 id="⭐哔哩哔哩api" tabindex="-1">⭐哔哩哔哩API <a class="header-anchor" href="#⭐哔哩哔哩api" aria-label="Permalink to &quot;⭐哔哩哔哩API&quot;">​</a></h2><h3 id="哔哩哔哩直播主要api-bili-liveapi" tabindex="-1">哔哩哔哩直播主要API（bili_liveapi） <a class="header-anchor" href="#哔哩哔哩直播主要api-bili-liveapi" aria-label="Permalink to &quot;哔哩哔哩直播主要API（bili_liveapi）&quot;">​</a></h3><ul><li>自定义哔哩哔哩直播主要 API，用于获取指定区域（大陆或海外）的直播流链接，默认使用官方 API。</li></ul><h3 id="哔哩哔哩直播回退api-bili-fallback-api" tabindex="-1">哔哩哔哩直播回退API（bili_fallback_api） <a class="header-anchor" href="#哔哩哔哩直播回退api-bili-fallback-api" aria-label="Permalink to &quot;哔哩哔哩直播回退API（bili_fallback_api）&quot;">​</a></h3><h3 id="直播cdn-bili-cdn" tabindex="-1">直播CDN（bili_cdn） <a class="header-anchor" href="#直播cdn-bili-cdn" aria-label="Permalink to &quot;直播CDN（bili_cdn）&quot;">​</a></h3><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>⭐海外机器录制需要一个国内的机器来反代<code>https://api.live.bilibili.com</code>这个域名，并将哔哩哔哩直播回退API（bili_fallback_api）设置为官方API。</li><li>⭐使用「streamlink」下载插件（downloader），最后设置优选「cn-gotcha204,ov-gotcha05」两个节点。 这样大主播可以使用<code>cn204</code>的fmp4流稳定录制。</li><li><code>cn-gotcha204</code>为官方节点，非<code>地方</code>节点，录制更稳定。</li><li>反代机器只作为<code>请求</code>使用，并不会耗费很多<code>流量/带宽</code>。</li></ul></div><h3 id="cdn回退-bili-cdn-fallback" tabindex="-1">CDN回退（bili_cdn_fallback） <a class="header-anchor" href="#cdn回退-bili-cdn-fallback" aria-label="Permalink to &quot;CDN回退（bili_cdn_fallback）&quot;">​</a></h3><ul><li>⭐默认为关闭。例如海外机器优选<code>ov0</code>之后，如果<code>ov05</code>流一直无法下载，将会自动回退到<code>ov07</code>进行下载。仅限<code>相同流协议</code>，建议打开。</li></ul><hr><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><ul><li>以下内容如果你不知道是做什么的，那么就不需要修改，也不要自作聪明的修改。</li></ul></div><h2 id="免登录原画-bili-anonymous-origin" tabindex="-1">免登录原画（bili_anonymous_origin） <a class="header-anchor" href="#免登录原画-bili-anonymous-origin" aria-label="Permalink to &quot;免登录原画（bili_anonymous_origin）&quot;">​</a></h2><ul><li>使用自定义API获取 master.m3u8 内的 hls_fmp4 原画流，无法录制特殊直播。默认关闭。</li></ul><h2 id="海外转大陆-bili-ov2cn" tabindex="-1">海外转大陆（bili_ov2cn） <a class="header-anchor" href="#海外转大陆-bili-ov2cn" aria-label="Permalink to &quot;海外转大陆（bili_ov2cn）&quot;">​</a></h2><ul><li>将海外cdn域名替换为大陆cdn域名，默认关闭。</li><li>例：将海外的<code>ov-gotcha07</code>替换为<code>cn-gotcha07</code>，直播cdn处仍然填写<code>ov-gotcha07</code>。</li></ul><h2 id="强制获取真原画-bili-force-source" tabindex="-1">强制获取真原画（bili_force_source） <a class="header-anchor" href="#强制获取真原画-bili-force-source" aria-label="Permalink to &quot;强制获取真原画（bili_force_source）&quot;">​</a></h2><ul><li>移除streamName的二压小尾巴（仅限<code>hls_fmp4</code>流，且画质等级<code>bili_qn &gt;= 10000</code>），默认为关闭，不保证可用性。</li></ul><h2 id="标准化-cn204-bili-normalize-cn204" tabindex="-1">标准化 CN204（bili_normalize_cn204） <a class="header-anchor" href="#标准化-cn204-bili-normalize-cn204" aria-label="Permalink to &quot;标准化 CN204（bili_normalize_cn204）&quot;">​</a></h2><ul><li>去除<code>cn-gotcha204</code>后面的小尾巴（-[1-4]）,例如<code>cn-gotcha204-3</code>开启后，会变成<code>cn-gotcha204</code>。</li></ul><h2 id="hls-fmp4-转码等待时间-bili-hls-transcode-timeout" tabindex="-1">hls_fmp4 转码等待时间（bili_hls_transcode_timeout） <a class="header-anchor" href="#hls-fmp4-转码等待时间-bili-hls-transcode-timeout" aria-label="Permalink to &quot;hls_fmp4 转码等待时间（bili_hls_transcode_timeout）&quot;">​</a></h2><ul><li>默认即可，用于<code>hls_fmp4</code>转码等待时间，超时后回退到<code>flv</code>流。默认60秒。</li></ul><h2 id="替换-cn01-sid-bili-replace-cn01" tabindex="-1">替换 CN01 sid (bili_replace_cn01) <a class="header-anchor" href="#替换-cn01-sid-bili-replace-cn01" aria-label="Permalink to &quot;替换 CN01 sid (bili_replace_cn01)&quot;">​</a></h2><ul><li>该功能在<code>强制获取真原画</code>之前生效，如果你不知道这是什么，那么就不要动他。</li></ul>',48)]))}const k=l(c,[["render",d]]);export{u as __pageData,k as default};
